#define THREADS 256

inline int mirror_coord(int d, int sizeD)
{
    if (sizeD <= 1) return 0;
    while (d < 0 || d >= sizeD) {
        if (d < 0) {
            d = -d;
        }
        if (d >= sizeD) {
            d = 2 * sizeD - 2 - d;
        }
    }
    return d;
}

inline int read_pixel(__global const int *input, int sx, int sy, int x, int y)
{
    int mx = mirror_coord(x, sx);
    int my = mirror_coord(y, sy);
    return input[my * sx + mx];
}

inline int row_detail53(__global const int *input, int sx, int sy, int xodd, int y)
{
    const int c = read_pixel(input, sx, sy, xodd, y);
    const int p = read_pixel(input, sx, sy, xodd - 1, y);
    const int n = read_pixel(input, sx, sy, xodd + 1, y);
    return c - ((p + n) / 2);
}

inline int row_approx53(__global const int *input, int sx, int sy, int xeven, int y)
{
    const int c  = read_pixel(input, sx, sy, xeven, y);
    const int dl = row_detail53(input, sx, sy, xeven - 1, y);
    const int dr = row_detail53(input, sx, sy, xeven + 1, y);
    return c + ((dl + dr + 2) / 4);
}

inline int col_detail53_low(__global const int *input, int sx, int sy, int xlow, int yodd)
{
    const int xeven = 2 * xlow;
    const int c = row_approx53(input, sx, sy, xeven, yodd);
    const int p = row_approx53(input, sx, sy, xeven, yodd - 1);
    const int n = row_approx53(input, sx, sy, xeven, yodd + 1);
    return c - ((p + n) / 2);
}

inline int col_approx53_low(__global const int *input, int sx, int sy, int xlow, int yeven)
{
    const int xeven = 2 * xlow;
    const int c  = row_approx53(input, sx, sy, xeven, yeven);
    const int dl = col_detail53_low(input, sx, sy, xlow, yeven - 1);
    const int dr = col_detail53_low(input, sx, sy, xlow, yeven + 1);
    return c + ((dl + dr + 2) / 4);
}

inline int col_detail53_high(__global const int *input, int sx, int sy, int xhigh, int yodd)
{
    const int xodd = 2 * xhigh + 1;
    const int c = row_detail53(input, sx, sy, xodd, yodd);
    const int p = row_detail53(input, sx, sy, xodd, yodd - 1);
    const int n = row_detail53(input, sx, sy, xodd, yodd + 1);
    return c - ((p + n) / 2);
}

inline int col_approx53_high(__global const int *input, int sx, int sy, int xhigh, int yeven)
{
    const int xodd = 2 * xhigh + 1;
    const int c  = row_detail53(input, sx, sy, xodd, yeven);
    const int dl = col_detail53_high(input, sx, sy, xhigh, yeven - 1);
    const int dr = col_detail53_high(input, sx, sy, xhigh, yeven + 1);
    return c + ((dl + dr + 2) / 4);
}

__kernel void c_CopySrcToComponents(__global int *d_r,
                                    __global int *d_g,
                                    __global int *d_b,
                                    __global const uchar *d_src,
                                    int pixels)
{
    int gid = (int)get_global_id(0);
    int gsz = (int)get_global_size(0);

    for (int pos = gid; pos < pixels; pos += gsz) {
        int base = pos * 3;
        d_r[pos] = (int)d_src[base + 0] - 128;
        d_g[pos] = (int)d_src[base + 1] - 128;
        d_b[pos] = (int)d_src[base + 2] - 128;
    }
}

__kernel void c_CopySrcToComponent(__global int *d_c,
                                   __global const uchar *d_src,
                                   int pixels)
{
    int gid = (int)get_global_id(0);
    int gsz = (int)get_global_size(0);

    for (int pos = gid; pos < pixels; pos += gsz) {
        d_c[pos] = (int)d_src[pos] - 128;
    }
}

__kernel void cl_fdwt53Kernel(__global const int *input,
                              __global int *output,
                              int sizeX,
                              int sizeY,
                              int winSteps,
                              int WIN_SX,
                              int WIN_SY)
{
    const int x = (int)get_global_id(0);
    const int groupY = (int)get_group_id(1);

    const int tileH = WIN_SY * winSteps;
    const int yStart = groupY * tileH;
    const int yEnd = min(sizeY, yStart + tileH);

    const int llx = (sizeX + 1) / 2;
    const int hlx = sizeX / 2;
    const int lly = (sizeY + 1) / 2;
    const int lhy = sizeY / 2;

    const int offLL = 0;
    const int offHL = llx * lly;
    const int offLH = offHL + hlx * lly;
    const int offHH = offLH + llx * lhy;

    if (x < llx) {
        for (int ry = (yStart + 1) / 2; (2 * ry) < yEnd; ++ry) {
            output[offLL + ry * llx + x] = col_approx53_low(input, sizeX, sizeY, x, 2 * ry);
        }
        for (int ry = yStart / 2; (2 * ry + 1) < yEnd; ++ry) {
            output[offLH + ry * llx + x] = col_detail53_low(input, sizeX, sizeY, x, 2 * ry + 1);
        }
    }

    if (x < hlx) {
        for (int ry = (yStart + 1) / 2; (2 * ry) < yEnd; ++ry) {
            output[offHL + ry * hlx + x] = col_approx53_high(input, sizeX, sizeY, x, 2 * ry);
        }
        for (int ry = yStart / 2; (2 * ry + 1) < yEnd; ++ry) {
            output[offHH + ry * hlx + x] = col_detail53_high(input, sizeX, sizeY, x, 2 * ry + 1);
        }
    }
}
